#define _GNU_SOURCE
#include <sched.h>
#include <stdio.h>
#include <stdlib.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <unistd.h>

#define STACK_SIZE (1024 * 1024)

static char child_stack[STACK_SIZE];

static int child_fn(void *arg) {
    printf("[child] PID inside namespace: %d\n", getpid());
    // mount a new procfs so /proc is namespace-filtered
    system("mount -t proc proc /proc");
    system("ps aux");
    return 0;
}

int main(void) {
    pid_t child = clone(
        child_fn,
        child_stack + STACK_SIZE,
        CLONE_NEWPID | CLONE_NEWNS | SIGCHLD, // CLONE_NEWNS for /proc
        NULL
    );
    if (child < 0) { perror("clone"); exit(1); }
    printf("[host] child host PID: %d\n", child);
    waitpid(child, NULL, 0);
    return 0;
}
// Compile: gcc -o ns_demo ns_demo.c
// Run:     sudo ./ns_demo
// Output:  [host] child host PID: 7412
//          [child] PID inside namespace: 1
